import numpy as np
import tensorflow.keras.backend as K

from psanp.classifiers.tensorflow.susann_v2_classifier.settings import Settings


def NetworkLoss(settings: Settings):
    eps = 1e-17

    def loss_wrapper(y_true, y_pred):
        class_gt_flat = y_true[..., 0]
        class_gt = K.one_hot(K.cast(class_gt_flat, "int32"), settings.data.n_classes)
        weights_gt = y_true[..., 1]

        # class_predictions = K.one_hot(K.cast(y_pred, 'int32'), settings.data.n_classes)
        # print(class_predictions.shape)
        class_predictions = y_pred

        # Compute the cross entropy
        class_predictions = K.clip(
            class_predictions, K.epsilon(), 1.0 - K.epsilon()
        )  # prevents numerical instability
        if settings.network.loss in {"focal", "wfocal"}:
            cross_entropy = -K.log(class_predictions) * class_gt
            focal_loss = cross_entropy * (
                class_gt * K.pow(1.0 - class_predictions, 2.0)
            )
            if settings.network.loss == "wfocal":
                loss = K.sum(K.sum(focal_loss, axis=-1) * weights_gt) / (
                    K.sum(weights_gt) + K.epsilon()
                )
            else:
                loss = K.mean(focal_loss)
        elif settings.network.loss == "cross_entropy":  # Default is cross entropy
            loss = K.mean(-K.log(class_predictions + eps) * class_gt)
        elif settings.network.loss in ("dice", "wdice"):
            numerator = 2 * K.sum(class_predictions * class_gt, axis=(0, 1, 2, 3)) + eps
            denominator = (
                K.sum(class_predictions, axis=(0, 1, 2, 3))
                + K.sum(class_gt, axis=(0, 1, 2, 3))
                + eps
            )
            if settings.network.loss == "wdice":
                loss = K.sum(
                    (1 - (numerator / denominator))
                    * np.array(settings.data.class_weights)
                )
            else:
                loss = K.mean(1 - (numerator / denominator))
        else:
            raise NotImplementedError

        return loss

    return loss_wrapper


def NetworkMetricIoU(settings: Settings):
    eps = 1e-17

    def iou_score(y_true, y_pred):
        class_gt_flat = y_true[..., 0]
        weights_gt = y_true[..., 1:2]
        class_gt = K.one_hot(K.cast(class_gt_flat, "int32"), settings.data.n_classes)

        class_predictions = K.one_hot(
            K.argmax(y_pred, axis=-1), settings.data.n_classes
        )
        # class_predictions = K.one_hot(K.cast(y_pred, 'int32'), settings.data.n_classes)

        intersection = K.sum(class_predictions * class_gt * weights_gt, axis=(0, 1, 2))
        union = K.sum(
            (class_gt + class_predictions - class_predictions * class_gt) * weights_gt,
            axis=(0, 1, 2),
        )
        return K.mean(intersection / (union + eps))

    return iou_score
